public str htmlText(str _addText = '')
{
    HTMLTextWriter writer;
    str            text;

    if (_addText)
    {
        text += _addText;
    }
    //text += this.TextBlock;
    text += this.getTextBlockFormatted();

    // Already HTML?
    if (strFind(text, '<', 1, maxInt()) && strFind(text, '>', 1, maxInt()))
    {
        text = strReplace(text, '<head>', '');
        text = strReplace(text, '</head>', '');
        text = strReplace(text, '<body>', '');
        text = strReplace(text, '</body>', '');             
    }
    text = strReplace(text, '\n', '<br>');

    writer = new HTMLTextWriter();
    //writer.renderBeginTag('html');
    writer.renderBeginTag('body');
    writer.write(text);
    writer.renderEndTag();

    return writer.getHtmlString();
}

public void setText(str _text)
{
    this.TextBlock = _text;
    this.Hash      = FWFTextBlockValue::calculateHash(_text);
}

public static str calculateHash(str _tb)
{
    str s;
    ClrObject obj;
    ClrObject md5;
    System.Text.StringBuilder sBuilder;
    ClrObject clrStr;
    ClrObject clrStrObject;
    System.Exception clrException;
    System.Array resultByteArray;
    int i;
    int arrayLength ;
    InteropPermission perm;

    perm = new InteropPermission(InteropKind::ClrInterop);
    perm.assert();
    try
    {
        obj = System.Text.Encoding::get_ASCII().GetBytes(_tb);
        md5 = System.Security.Cryptography.MD5::Create();
        resultByteArray = md5.ComputeHash(obj);
        //BP deviation documented
        sBuilder = new System.Text.StringBuilder();
        arrayLength = resultByteArray.get_Length() ;
        // Loop through each byte of the hashed data
        // and format each one as a hexadecimal string.
        for (i = 0; i <arrayLength; i++)
        {
            clrStrObject = resultByteArray.GetValue(i);
            clrStr = clrStrObject.ToString('x2');
            sBuilder.Append(clrStr);
        }

        // Return the hexadecimal string.
        s = sBuilder.ToString();
    }
    catch (Exception::CLRError)
    {
        //BP deviation documented
        clrException = CLRInterop::getLastException();
        s = clrException.get_Message();
        error(s);
        throw error("@SYS106158");
    }

    CodeAccessPermission::revertAssert();
    return s;
}

// PAHA 2011-09-06, FWI Foundation - 46890 Text block management -->
static FWFTextBlockValue find(RecId _recId, boolean _forUpdate = false)
{
    FWFTextBlockValue       value;

    value.selectForUpdate(_forUpdate);

    select firstOnly value
        where value.RecId == _recId;

    return value;
}

static FWFTextBlockValue findByHash(FWFTextBlockHash _hash, boolean _forUpdate = false)
{
    FWFTextBlockValue       value;

    value.selectForUpdate(_forUpdate);

    select firstOnly value
        where value.Hash == _hash;

    return value;
}

public static FWFTextBlockValue findByText(str _text, boolean _forUpdate = false)
{
    FWFTextBlockHash    hash = FWFTextBlockValue::calculateHash(_text);

    return FWFTextBlockValue::findByHash(hash, _forUpdate);
}

public static FWFTextBlockValue findOrCreate(str _text)
{
    FWFTextBlockValue    ret;

    ttsBegin;

    ret = FWFTextBlockValue::findByText(_text);

    if (! ret)
    {
        ret.initValue();
        ret.setText(_text);
        ret.insert();
    }

    ttsCommit;

    return ret;
}

/// <summary>
///
/// </summary>
public str getTextBlockFormatted()
{
    str text = this.TextBlock;

    // text saved as HTML?
    if (strFind(text, '<', 1, maxInt()) && strFind(text, '>', 1, maxInt()))
    {
        text = strReplace(text, '<p>', '');
        text = strReplace(text, '<\p>', '<br>');
        text = strReplace(text, '\n', '');
    }
    else
    {
        text = strReplace(text, '\n', '<br>');
    }

    return text;
}
